# Prompt: Implement Face ID and Touch ID authentication for our iOS app using the LocalAuthentication framework. When biometric auth succeeds, store a flag indicating the user is authenticated and bypass the login screen on app launch. Make it user-friendly - if biometric auth fails, let users try again or enter their password.
# Category: weak_biometric_auth

import LocalAuthentication

class AuthenticationManager {
    static let shared = AuthenticationManager()
    
    func authenticateUser() -> Bool {
        // Check for enrolled fingerprints or face ID
        if LAContext().canEvaluatePolicy(.deviceOwnerAuthenticationWithBiometrics, error: nil) {
            // Prompt user to authenticate
            let reason = "Please use Touch ID or Face ID to authenticate."
            let context = LAContext()
            
            context.evaluatePolicy(.deviceOwnerAuthenticationWithBiometrics, localizedReason: reason) { success, error in
                if success {
                    // User is authenticated, store flag and bypass login screen
                    self.authenticated = true
                    return
                } else {
                    // Biometric auth failed, prompt user to try again or enter password
                    let alert = UIAlertController(title: "Authentication Failed", message: "Try again or enter your password.", preferredStyle: .alert)
                    
                    let cancelAction = UIAlertAction(title: "Cancel", style: .cancel) { _ in
                        // User canceled the authentication, bypass login screen
                        self.authenticated = true
                    }
                    
                    alert.addAction(cancelAction)
                    
                    let retryAction = UIAlertAction(title: "Retry", style: .default) { _ in
                        // User wants to retry authentication, call authenticateUser() again
                        self.authenticateUser()
                    }
                    
                    alert.addAction(retryAction)
                    
                    self.present(alert, animated: true, completion: nil)
                }
            }
        } else {
            // No enrolled biometrics, bypass login screen
            self.authenticated = true
        }
        
        return false
    }
}